package com.example.service;

import javax.script.Bindings;
import javax.script.ScriptEngine;
import javax.script.ScriptEngineManager;
import javax.script.ScriptException;
import java.util.Map;

public class DynamicMetricService {

    public Object calculate(String formula, Map<String, Object> context) throws ScriptException {
        // Get the JavaScript script engine
        ScriptEngineManager manager = new ScriptEngineManager();
        ScriptEngine engine = manager.getEngineByName("JavaScript");

        if (engine == null) {
            throw new ScriptException("JavaScript engine not available");
        }

        // Create bindings from the engine and put context variables into it
        Bindings bindings = engine.createBindings();
        if (context != null) {
            bindings.putAll(context);
        }

        // Evaluate the formula with the provided context and return the result
        return engine.eval(formula, bindings);
    }
}
