public class DynamicMetricService {

    private final ScriptEngine engine;

    public DynamicMetricService() {
        // Obtain the JavaScript (Nashorn) engine
        // Note: Nashorn is available by default in Java 8-14. For Java 15+, an external engine is needed.
        this.engine = new ScriptEngineManager().getEngineByName("JavaScript");
