     * @param context  A map containing variable names and their corresponding values
     * @return The computed result
     * @throws ScriptException if the engine is unavailable or the formula fails
     */
    public Object calculate(String formula, Map<String, Object> context) throws ScriptException {
        if (engine == null) {
            throw new ScriptException("JavaScript engine not available");
        }

        if (context == null) {
            throw new IllegalArgumentException("Context map cannot be null");
        }

        // Use SimpleBindings to create an isolated scope for variables.
        // This ensures thread safety and prevents variable leakage between requests.
        SimpleBindings bindings = new SimpleBindings(context);

